const raw = $input.first().json;
const msg = raw.message || raw.callback_query?.message || {};
const from = raw.message?.from || raw.callback_query?.from || {};
const cb = raw.callback_query;

const userId = String(from.id || '');
const chatId = String(msg.chat?.id || from.id || '');
const username = from.username || '';
const firstName = from.first_name || '';

let type = 'unknown';
let text = '';
if (cb) { type = 'callback'; text = cb.data || ''; }
else if (msg.voice) { type = 'voice'; text = ''; }
else if (msg.photo) { type = 'photo'; text = msg.caption || ''; }
else if (msg.document) { type = 'document'; text = msg.caption || ''; }
else if (msg.text) { type = 'text'; text = msg.text; }

const startTs = Date.now();

return [{ json: {
  startTs,
  userId, chatId, username, firstName, type, text,
  messageId: msg.message_id || null,
  callbackQueryId: cb?.id || null,
  callbackMessageId: cb?.message?.message_id || null,
  voiceFileId: msg.voice?.file_id || null,
  voiceDurationSec: msg.voice?.duration || null,
  photoFileId: msg.photo ? msg.photo[msg.photo.length - 1].file_id : null,
  documentFileId: msg.document?.file_id || null,
  documentName: msg.document?.file_name || null,
  raw,
} }];

const msg = $('Normalize').first().json;
const users = $input.all().map((i) => i.json);
const user = users.find((u) => u.fields?.Active === true) || null;
if (!user) return [{ json: { ...msg, authorized: false } }];
return [{ json: { ...msg, authorized: true, userFields: user.fields } }];

const msg = $('Auth').first().json;
// OpenAI node returns transcription either in .text or .transcription
const out = $input.first().json;
const transcript = (out.text || out.transcription || '').trim();
return [{ json: { ...msg, text: transcript, type: 'text', fromVoice: true } }];

// Decide routing: command (handled locally) or natural (send to GPT)
let msg;
try {
  const vt = $('VoiceToText').first();
  msg = (vt && vt.json && vt.json.fromVoice) ? vt.json : $('Auth').first().json;
} catch (e) {
  msg = $('Auth').first().json;
}
const schedule = $input.first().json;
const text = (msg.text || '').trim();
const lower = text.toLowerCase();

// Commands that don't need GPT
const isStart = (lower === '/start' || lower.startsWith('/start '));
const isHelp = (lower === '/help' || lower === '/помощь');
const isGantt = (lower === '/график' || lower === '/gantt');
const isStatus = (lower === '/статус' || lower === '/status');
const isCancel = (lower === '/отмена' || lower === '/cancel');

// Unsupported types
const unsupported = (msg.type === 'photo' || msg.type === 'document');

const needsGPT = !isStart && !isHelp && !isGantt && !isStatus && !isCancel && !unsupported && text.length > 1;

return [{ json: { ...msg, schedule, needsGPT, commandType: isStart?'start':isHelp?'help':isGantt?'gantt':isStatus?'status':isCancel?'cancel':unsupported?'unsupported':null } }];

// Merge GPT output into msg context.
const msg = $('PreClassify').first().json;
const gpt = $input.first().json;
let parsed = null;
try {
  parsed = JSON.parse(gpt.choices[0].message.content);
} catch (e) {
  parsed = { intent: 'unknown', confidence: 0, clarify_question: 'Не смог разобрать твой запрос. Переформулируй?' };
}
return [{ json: { ...msg, gpt: parsed } }];

// Build final response. Returns: responseText, pendingAction, useKeyboard, intent.
const msg = $input.first().json;
const schedule = msg.schedule;
const name = msg.userFields?.Name || msg.firstName || 'друг';
const GANTT = 'https://cyfr-schedule-app.vercel.app/';
const TODAY = new Date();
const today = TODAY.toISOString().slice(0, 10);

function fmtDate(iso) {
  if (!iso) return '?';
  const d = new Date(iso);
  return d.toLocaleDateString('ru-RU', { day: 'numeric', month: 'long' });
}
function fmtDur(start, end) {
  if (!start || !end) return '';
  const d = Math.round((new Date(end) - new Date(start)) / 86400000);
  return `${d} дн.`;
}
function findTask(q) {
  if (!q) return [];
  const needle = q.toLowerCase();
  let t = schedule.tasks.find(x => x.id === q);
  if (t) return [t];
  let matches = schedule.tasks.filter(x => x.name.toLowerCase().includes(needle));
  if (matches.length) return matches;
  const sec = schedule.sections.find(s => s.id === needle || s.name.toLowerCase().includes(needle));
  if (sec) return schedule.tasks.filter(x => x.section === sec.id);
  return [];
}
function findSection(q) {
  if (!q) return null;
  const needle = q.toLowerCase().trim();
  // Slang / Russian name aliases → section ID
  const ALIASES = {
    'малярка':'paint','покраска':'paint','маляр':'paint','красить':'paint',
    'штукатурка':'finishing','финишка':'finishing','шпаклёвка':'finishing','шпатлёвка':'finishing','штукатурно':'finishing',
    'электрика':'electrical','электро':'electrical','проводка':'electrical',
    'сантехника':'plumbing','сантех':'plumbing','водопровод':'plumbing','канализация':'plumbing',
    'демонтаж':'demolition','демонт':'demolition','снос':'demolition',
    'вентиляция':'hvac','овик':'hvac','кондиционер':'hvac','фанкоил':'hvac','воздуховод':'hvac',
    'пожарка':'fire_safety','пожаробезопасность':'fire_safety','пожарная':'fire_safety',
    'гк��':'drywall','гипсокартон':'drywall','перегородки':'drywall','каркас':'drywall',
    'полы':'flooring','стяжка':'flooring','плитка':'flooring','ковролин':'flooring','наливной':'flooring',
    'стекло':'glass','стеклянные':'glass','перегородка стекло':'glass',
    'мебель':'furniture','декор':'furniture',
    'уборка':'cleaning','генеральная':'cleaning',
    'логистика':'materials','материалы':'materials','доставка':'materials',
  };
  for (const [alias, id] of Object.entries(ALIASES)) {
    if (needle.includes(alias)) return schedule.sections.find(s => s.id === id);
  }
  return schedule.sections.find(s => s.id === needle || s.name.toLowerCase().includes(needle));
}
function taskLine(t) {
  return `• _${t.name}_ (${fmtDate(t.planStart)} → ${fmtDate(t.planEnd)})`;
}
function ambiguousReply(candidates) {
  return `🔍 Нашёл несколько похожих задач:\n\n${candidates.slice(0,5).map(taskLine).join('\n')}\n\nУточните полным названием или датой — например _«которая на май»_ или _«монтаж оборудования»_.`;
}
function notFoundReply(q) {
  return `🤔 Не нашёл задачу «${q || '?'}». Попробуй точнее или /график.`;
}

// ── Query helpers ──
function statusText() {
  const p = schedule.project;
  const tasks = schedule.tasks.filter(t => !t.cancelled);
  const start = new Date(p.startDate), end = new Date(p.endDate);
  let pctTime = 0;
  if (TODAY < start) pctTime = 0;
  else if (TODAY > end) pctTime = 100;
  else pctTime = Math.round(((TODAY - start) / (end - start)) * 100);
  const pctWork = tasks.length ? Math.round(tasks.reduce((s,t) => s + taskPct(t), 0) / tasks.length) : 0;
  const cntDone = tasks.filter(isDone).length;
  const cntRun  = tasks.filter(isRunning).length;
  const cntWait = tasks.filter(t => !isDone(t) && !isRunning(t)).length;
  const overdue = tasks.filter(isOverdue);
  const running = tasks.filter(isRunning).slice(0, 5);
  const runLines = running.map(t => `🟡 _${t.name}_ ${taskPct(t)}%`).join('\n');
  const overdueList = overdue.slice(0,5).map(t => {
    const dd = Math.round((TODAY - new Date(t.planEnd||t.end)) / 86400000);
    return `🔴 _${t.name}_ — ${dd} дн. просрочки`;
  }).join('\n');
  let updLine = p.lastUpdated ? `\n🕐 Обновле��о: ${fmtDate(p.lastUpdated)}${p.lastUpdatedBy ? ' · '+p.lastUpdatedBy : ''}` : '';
  let out = `📊 *${p.name}*\n\n⏱ Время: *${pctTime}%* пройдено\n✅ Р��боты: *${pctWork}%* (${cntDone} из ${tasks.length} завершено)\n\n🟡 В работе: ${cntRun}\n⚪️ Не начато: ${cntWait}\n🔴 Просрочено: ${overdue.length}`;
  if (running.length) out += `\n\n*Сейчас в работе:*\n${runLines}`;
  if (overdue.length) out += `\n\n*Просрочки:*\n${overdueList}`;
  out += updLine + `\n\n🔗 ${GANTT}`;
  return out;
}
function todayText() {
  const tasks = schedule.tasks.filter(t => !t.cancelled && !isDone(t)).filter(t => {
    const ps = new Date(t.planStart || t.start), pe = new Date(t.planEnd || t.end);
    return ps <= TODAY && TODAY <= pe;
  });
  if (!tasks.length) return `📅 На сегодня нет активных задач по плану.\n\n🔗 ${GANTT}`;
  const lines = tasks.map(t => {
    const pe = new Date(t.planEnd || t.end);
    const dd = Math.round((pe - TODAY) / 86400000);
    const pctStr = t.progress > 0 ? ` ${Math.round(t.progress*100)}%` : '';
    const icon = isOverdue(t) ? '🔴' : isRunning(t) ? '🟡' : '⚪️';
    let row = `${icon} *${t.name}*${pctStr}`;
    row += `\n   📐 план: ${fmtDate(t.planStart)} → ${fmtDate(t.planEnd)}`;
    if (t.actualStart) row += `\n   🚀 начали: ${fmtDate(t.actualStart)}`;
    row += `\n   ⏳ до конца: ${dd > 0 ? dd+' дн.' : dd === 0 ? 'сегодня дедлайн!' : Math.abs(dd)+' дн. просрочки'}`;
    return row;
  }).join('\n\n');
  return `📅 *Сегодня по плану (${tasks.length}):*\n\n${lines}\n\n🔗 ${GANTT}`;
}
function overdueText() {
  const overdue = schedule.tasks.filter(t => !t.cancelled && isOverdue(t));
  if (!overdue.length) return `🎉 Нет просроченных задач!`;
  const lines = overdue.slice(0,10).map(t => {
    const dd = Math.round((TODAY - new Date(t.planEnd||t.end)) / 86400000);
    const pctStr = t.progress > 0 ? ` ${Math.round(t.progress*100)}%` : '';
    let row = `🔴 *${t.name}*${pctStr} — ${dd} дн. просрочки`;
    row += `\n   📐 план: ${fmtDate(t.planStart)} → ${fmtDate(t.planEnd)}`;
    if (t.actualStart) row += `\n   🚀 начали: ${fmtDate(t.actualStart)}`;
    else row += `\n   ⚪️ ещё не начата`;
    return row;
  }).join('\n\n');
  return `⚠️ *Просрочено задач: ${overdue.length}*\n\n${lines}\n\n🔗 ${GANTT}`;
}
// ── Status helpers ──
function isDone(t)    { return t.progress >= 1; }
function isRunning(t) { return !isDone(t) && (t.progress > 0 || !!t.actualStart); }
function isOverdue(t) { return !isDone(t) && new Date(t.planEnd || t.end) < TODAY; }
function taskPct(t)   { return isDone(t) ? 100 : t.progress > 0 ? Math.round(t.progress * 100) : (t.actualStart ? 5 : 0); }

function sectionText(q) {
  const sec = findSection(q);
  if (!sec) return `🤔 Не нашёл секцию «${q}». Список: ${schedule.sections.map(s=>s.name).join(', ')}.`;
  const tasks = schedule.tasks.filter(t => t.section === sec.id && !t.cancelled);
  if (!tasks.length) return `📂 *${sec.name}* — нет задач.`;
  const totalPct = Math.round(tasks.reduce((s, t) => s + taskPct(t), 0) / tasks.length);
  const lines = tasks.map(t => {
    const icon = isDone(t) ? '✅' : isOverdue(t) ? '🔴' : isRunning(t) ? '🟡' : '⚪️';
    const pctStr = !isDone(t) && t.progress > 0 ? ` ${Math.round(t.progress*100)}%` : '';
    const ovdStr = isOverdue(t) ? ` — ⚠️ просрочено ${Math.round((TODAY - new Date(t.planEnd||t.end))/86400000)} дн.` : '';
    let row = `${icon} *${t.name}*${pctStr}${ovdStr}`;
    row += `\n   📐 план: ${fmtDate(t.planStart)} → ${fmtDate(t.planEnd)}`;
    return row;
  }).join('\n\n');
  return `📂 *${sec.name}* — ${totalPct}%\n\n${lines}\n\n🔗 ${GANTT}`;
}
function periodText(periodStart, periodEnd) {
  if (!periodStart || !periodEnd) return `🤔 Не понял период. Например: _«что на следующей неделе»_, _«дедлайны до конца месяца»_, _«задачи в мае»_.`;
  const ps = new Date(periodStart), pe = new Date(periodEnd);
  const tasks = schedule.tasks.filter(t => {
    if (t.cancelled) return false;
    const ts = new Date(t.planStart || t.start), te = new Date(t.planEnd || t.end);
    return te >= ps && ts <= pe;
  });
  if (!tasks.length) return `📅 В период ${fmtDate(periodStart)} — ${fmtDate(periodEnd)} задач нет.\n\n🔗 ${GANTT}`;
  const deadlines = tasks.filter(t => {
    const te = new Date(t.planEnd || t.end);
    return te >= ps && te <= pe && !t.actualEnd;
  });
  const active = tasks.filter(t => !deadlines.includes(t));
  let out = `📅 *Период ${fmtDate(periodStart)} — ${fmtDate(periodEnd)}*\n`;
  if (deadlines.length) {
    out += `\n🎯 *Дедлайны (${deadlines.length}):*\n`;
    out += deadlines.map(t => {
      const icon = t.actualStart ? '🟡' : '⚪️';
      return `${icon} _${t.name}_ · до ${fmtDate(t.planEnd)}`;
    }).join('\n') + '\n';
  }
  if (active.length) {
    out += `\n▶️ *В работе в этот период (${active.length}):*\n`;
    out += active.slice(0, 10).map(t => {
      const icon = t.actualEnd ? '✅' : t.actualStart ? '🟡' : '⚪️';
      return `${icon} _${t.name}_ · ${fmtDate(t.planStart)}→${fmtDate(t.planEnd)}`;
    }).join('\n');
    if (active.length > 10) out += `\n_...и ещё ${active.length-10}_`;
  }
  return out + `\n\n🔗 ${GANTT}`;
}
function startText() {
  return `👋 Привет, ${name}!\n\nЯ помогаю вести график работ голосом или текстом.\n\n━━━━━━━━━━━━━━━\n📊 _«как дела»_ · _«статус»_ · _«что сегодня»_\n✅ _«электрика готова»_ · _«малярка на 60%»_\n📅 _«сдвинь потолки на 3 дня»_ · _«электрика с 10 по 25 мая»_\n➕ _«добавь монтаж кондиционеров»_ · _«убери вывоз мусора»_\n✏️ _«переименуй уборку»_ · _«перемести в чистовые»_\n👷 _«электрику делает бригада Ахмеда»_ · _«это наши силы»_\n📂 _«добавь раздел фасадные работы»_\n⚠️ _«задержка по малярке — ждём материал»_\n\n🔗 ${GANTT}`;
}
function helpText() {
  return `📋 *Всё что я умею — голосом или текстом:*

━━━ 📊 Смотреть график ━━━
• _«как дела»_ · _«статус»_ · _«прогресс»_
• _«что сегодня»_ · _«что идёт сейчас»_
• _«что просрочено»_ · _«где отстаём»_
• _«как электрика»_ · _«по сантехнике»_
• _«что на следующей неделе»_ · _«дедлайны в мае»_

━━━ ✅ Статус и прогресс ━━━
• _«электрика готова»_ · _«��акончили штукатурку»_
• _«малярка на 60%»_ · _«покраска почти готов��»_
• _«стяжку начали»_ · _«приступили к плитке»_
• _«отменить монтаж перегородок»_
• _«к сантехнике: проверить уклон»_ (заметка)
• _«задержка по малярке — ждём цвет»_

━━━ 📅 Сроки и даты ━━━
• _«сдвинь покраску на 5 дней»_
• _«электрика с 10 по 25 мая»_
• _«начало стяжки с 1 июня»_
• _«закончи монтаж к 20 мая»_
• _«укорати покраску до 14 дней»_
• _«все финишны�� сдвинь на неделю»_ (весь раздел)

━━━ ➕ Добавить и изменить ━━━
• _«добавь монтаж кондиционеров»_
• _«убери вывоз мусора»_
• _«переименуй уборку в генеральная уборка»_
• _«перемести сантехнику в черновые»_

━━━ 👷 Подрядчики ━━━
• _«электрику делает бригада Ахмеда»_
• _«это наши силы»_ · _«делаем сами»_
• _«все финишные — бригада Ивана»_

━━━ 📂 Разделы ━━━
• _«добавь раздел фасадные работы»_
• _«переименуй раздел»_ · _«удали раздел»_

━━━ ⚡️ Команды ━━━
/статус · /график · /отмена

🔗 ${GANTT}`;
}

// ─── Main logic ───
let responseText = '';
let intent = msg.commandType || 'unknown';
let pendingAction = null;
let useKeyboard = false;

if (msg.commandType === 'start') {
  responseText = startText();
} else if (msg.commandType === 'help') {
  responseText = helpText();
} else if (msg.commandType === 'gantt') {
  responseText = `🔗 Витрина:\n${GANTT}`;
} else if (msg.commandType === 'status') {
  responseText = statusText();
} else if (msg.commandType === 'cancel') {
  responseText = `❎ Нечего отменять.`;
} else if (msg.commandType === 'unsupported') {
  responseText = msg.type === 'photo'
    ? `📸 Фото — скоро (привязка к задаче через PlanRadar).`
    : `📄 Документы — скоро (PDF/Word сметы).`;
} else if (msg.gpt) {
  const g = msg.gpt;
  intent = g.intent;
  const tp = msg.fromVoice ? `🎤 _«${msg.text}»_\n\n` : '';

  // ── clarify_question от GPT ──
  if (g.clarify_question) {
    const lbl = {
      mark_complete:'✅ готово', mark_started:'🟡 старт', set_progress:'📊 %',
      shift_dates:'📅 сдвиг', add_delay:'⚠️ задержка', add_task:'➕ добавить',
      remove_task:'🗑 удалить', rename_task:'✏️ переименовать', set_contractor:'👷 подрядчик',
      set_start_date:'📅 дата начала', set_end_date:'📅 дата конца',
      bulk_shift_section:'📅 раздел сдвиг'
    };
    const sugg = (g.suggested_intents || []).filter(i => lbl[i]).slice(0, 4);
    const hint = sugg.length ? `\n\nВозможно:\n${sugg.map(i=>'• '+lbl[i]).join('\n')}` : '';
    responseText = `${tp}🤔 ${g.clarify_question}${hint}`;
    intent = 'clarify';

  // ── QUERIES ──
  } else if (g.intent === 'query_status')  { responseText = statusText(); }
  else if (g.intent === 'query_today')     {
    if (g.section) { responseText = sectionText(g.section); intent = 'info'; }
    else            { responseText = todayText(); }
  }
  else if (g.intent === 'query_overdue')   { responseText = overdueText(); }
  else if (g.intent === 'query_section')   { responseText = sectionText(g.section || g.task_query); }
  else if (g.intent === 'query_period')    { responseText = periodText(g.plan_start, g.plan_end); }
  else if (g.intent === 'show_help')       { responseText = helpText(); intent = 'help'; }
  else if (g.intent === 'greeting')        { responseText = `👋 Привет! Напиши _«статус»_ или диктуй что произошло.`; }
  else if (g.intent === 'smalltalk')       { responseText = g.clarify_question || `🤔 Чем помочь по проекту?`; }

  // ══════════════════════════════════════
  // СТАТУС / ПРОГРЕСС
  // ══════════════════════════════════════
  else if (['mark_complete','mark_started','set_progress','shift_dates','add_delay','mark_cancelled'].includes(g.intent)) {
    const cands = findTask(g.task_id || g.task_query);
    if (!cands.length) { responseText = notFoundReply(g.task_query || g.task_id); intent = 'task_not_found'; }
    else if (cands.length > 1) { responseText = ambiguousReply(cands); intent = 'task_ambiguous'; }
    else {
      const t = cands[0];
      const datePart = g.date ? fmtDate(g.date) : fmtDate(today);
      // Smart plan/actual detection for shift_dates
      if (g.intent === 'shift_dates') {
        const hasActual = !!(t.actualEnd || t.actualStart);
        const hasPlan   = !!(t.planEnd || t.planStart);
        let dateType = g.date_type || null;
        if (dateType === 'actual' && !hasActual && hasPlan) dateType = 'plan';
        if (dateType === 'plan'   && !hasPlan && hasActual) dateType = 'actual';
        if (!dateType) {
          if (!hasActual && hasPlan)       dateType = 'plan';
          else if (hasActual && !hasPlan)  dateType = 'actual';
        }
        const shiftStart = g.shift_start !== false;
        if (dateType === null) {
          // Both plan and actual exist — ask user with plan/actual keyboard
          const pa = { type: 'shift_dates', taskId: t.id, taskName: t.name, date: g.date || today, days: g.days, value: null, reason: null, dateType: null, shiftStart, clarifyDateType: true };
          return [{ json: { ...msg, intent: 'shift_dates', useKeyboard: true, responseText: `${tp}📅 Для «${t.name}» (${g.days > 0 ? '+' : ''}${g.days} дн.) — что переносим: план или факт?`, pendingAction: pa } }];
        }
        const _dtL = dateType === 'actual' ? 'факт' : dateType === 'both' ? 'план и факт' : 'план';
        const _stL = shiftStart ? 'начало и конец' : 'только конец';
        const pa = { type: 'shift_dates', taskId: t.id, taskName: t.name, date: g.date || today, days: g.days, value: null, reason: null, dateType, shiftStart };
