    cronResponseText = `✅ Принято! Ждём закрытия в срок.\nНе забудь отметить «готово» когда закончите 🔗 ${GANTT}`;
  } else if (outcome === 'shift') {
    pendingAction = { type: 'shift_dates', taskId, taskName: 'задача', days, dateType: 'plan', shiftStart: false, awaitingReason: true };
    awaitingReason = true;
    responseText = `📆 ОК, дедлайн сдвинем на +${days} дн.\n\nКакая причина задержки?`;
  }
}

return [{ json: {
  ...msg,
  pendingAction,
  cronResponseText: cronResponseText || '✅ Принято!',
  responseText,
  hasCronAction: pendingAction !== null && !awaitingReason,
  awaitingReason
} }];
